import * as https from "https";
import axios, { AxiosResponse } from "axios";

export async function createActionRequest(data: {
  startupServerUrl: string;
  jwt: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- suppress eslint warning
  form: Record<string, any>;
  enforceSecurityVerification?: boolean;
}): Promise<AxiosResponse> {
  // Ensure the URL ends with a slash before appending 'action'
  const reqUrl = data.startupServerUrl.endsWith("/")
    ? `${data.startupServerUrl}action`
    : `${data.startupServerUrl}/action`;

  const urlencodedForm = new URLSearchParams(
    Object.entries(data.form),
  ).toString();

  return axios.post(reqUrl, urlencodedForm, {
    httpsAgent: new https.Agent({
      rejectUnauthorized: data.enforceSecurityVerification ?? true,
    }),
    headers: {
      Authorization: `Bearer ${data.jwt}`,
      "Content-Type": "application/x-www-form-urlencoded",
    },
  });
}
